def apply_percentage_discount(price: float, discount_percent: float) -> float:
    """Returns price after applying a percentage discount."""
    if discount_percent < 0 or discount_percent > 100:
        raise ValueError(f"discount_percent must be between 0 and 100, got {discount_percent}")
